3_real_world_example.code:
const prices = [10, 20, 30];

// Regular function callback
const doubled1 = prices.map(function(p) {
  return p * 2;
});

// Arrow function callback (implicit return)
const doubled2 = prices.map(p => p * 2);

// Arrow function returning an object implicitly
const createItem = (name, price) => ({ name, price });
console.log(createItem('Apple', 2)); // { name: 'Apple', price: 2 }

